// ─── Pricing Helpers ──────────────────────────────────────────────────────────
const PRICE_TIERS = [
  { minBookings: 5, label: "Zoomies Mode", prices: { "30 min": 30, "60 min": 45 } },
  { minBookings: 3, label: "Park Regular", prices: { "30 min": 35, "60 min": 50 } },
  { minBookings: 1, label: "Couch Pup", prices: { "30 min": 40, "60 min": 55 } },
];

function getCurrentWeekRange() {
  const today = new Date();
  const dow = today.getDay();
  const offset = dow === 0 ? -6 : 1 - dow;
  const monday = new Date(today);
  monday.setDate(today.getDate() + offset);
  monday.setHours(0, 0, 0, 0);
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  sunday.setHours(23, 59, 59, 999);
  return { monday, sunday };
}

function getWeekRangeForOffset(weekOffset) {
  const today = new Date();
  const dow = today.getDay();
  const off = dow === 0 ? -6 : 1 - dow;
  const monday = new Date(today);
  monday.setDate(today.getDate() + off + weekOffset * 7);
  monday.setHours(0, 0, 0, 0);
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  sunday.setHours(23, 59, 59, 999);
  return { monday, sunday };
}

// Returns the ISO weekKey (Monday date) for any booking
function getBookingWeekKey(b) {
  const d = new Date(b.scheduledDateTime || b.completedAt || b.bookedAt);
  const dow = d.getDay();
  const off = dow === 0 ? -6 : 1 - dow;
  const monday = new Date(d);
  monday.setDate(d.getDate() + off);
  monday.setHours(0, 0, 0, 0);
  return monday.toISOString().slice(0, 10);
}

function getWeekBookingCountForOffset(bookings, weekOffset) {
  const { monday, sunday } = getWeekRangeForOffset(weekOffset);
  return (bookings || []).filter(b => {
    if (b.cancelled) return false;
    const d = new Date(b.scheduledDateTime || b.bookedAt);
    return d >= monday && d <= sunday;
  }).length;
}

function getWeekBookingCount(bookings) {
  const { monday, sunday } = getCurrentWeekRange();
  return (bookings || []).filter(b => {
    const d = new Date(b.bookedAt);
    return d >= monday && d <= sunday;
  }).length;
}

function getPriceTier(weekCount) {
  return PRICE_TIERS.find(t => weekCount >= t.minBookings) || PRICE_TIERS[2];
}

function getSessionPrice(duration, weekCount) {
  const tier = getPriceTier(weekCount);
  return tier.prices[duration] || tier.prices["30 min"];
}

function getWeekBookingDates(bookings) {
  const { monday, sunday } = getCurrentWeekRange();
  return (bookings || [])
    .filter(b => { const d = new Date(b.bookedAt); return d >= monday && d <= sunday; })
    .map(b => b.bookedAt);
}

function getWeekDiscount(weekCount) {
  if (weekCount >= 5) return { label: "Daily rate", saved30: 10, saved60: 10 };
  if (weekCount >= 3) return { label: "Regular rate", saved30: 5, saved60: 5 };
  return null;
}

function getCancellationPolicy(scheduledDateTime) {
  const now = new Date();
  const apptTime = new Date(scheduledDateTime);
  const hoursUntil = (apptTime - now) / (1000 * 60 * 60);
  if (hoursUntil > 24) return { penalty: 0, label: "Free cancellation", color: "#C4541A", canCancel: true };
  if (hoursUntil > 12) return { penalty: 0.5, label: "50% cancellation fee", color: "#b45309", canCancel: true };
  if (hoursUntil > 0)  return { penalty: 1.0, label: "100% cancellation fee", color: "#dc2626", canCancel: true };
  return { penalty: 1.0, label: "Appointment passed", color: "#9ca3af", canCancel: false };
}

function repriceWeekBookings(bookings) {
  // Find all bookings in the current week, sorted by bookedAt
  const { monday, sunday } = getCurrentWeekRange();
  const weekIdxs = [];
  bookings.forEach((b, i) => {
    const d = new Date(b.bookedAt);
    if (d >= monday && d <= sunday && !b.cancelled) weekIdxs.push(i);
  });
  // Reprice based on total count
  const count = weekIdxs.length;
  const tier = getPriceTier(count);
  const updated = [...bookings];
  weekIdxs.forEach(i => {
    const basePrice = tier.prices[updated[i].slot?.duration] || tier.prices["30 min"];
    const dogCharge = (updated[i].additionalDogCount || 0) * 10;
    updated[i] = { ...updated[i], price: basePrice + dogCharge, priceTier: tier.label, sameDayDiscount: false };
  });
  return updated;
}

function applySameDayDiscount(bookings) {
  // Group active bookings by calendar date (YYYY-MM-DD of scheduledDateTime)
  const byDate = {};
  bookings.forEach((b, i) => {
    if (b.cancelled || !b.scheduledDateTime) return;
    const dateKey = b.scheduledDateTime.slice(0, 10);
    if (!byDate[dateKey]) byDate[dateKey] = [];
    byDate[dateKey].push(i);
  });
  const updated = [...bookings];
  // First pass: strip all existing same-day discounts to get clean base prices
  updated.forEach((b, i) => {
    if (b.sameDayDiscount && b.priceBeforeSameDayDiscount != null) {
      updated[i] = {
        ...b,
        price: b.priceBeforeSameDayDiscount,
        priceBeforeSameDayDiscount: undefined,
        sameDayDiscount: false,
      };
    }
  });
  // Second pass: apply 20% only to days that have exactly 2+ active bookings
  Object.values(byDate).forEach(idxs => {
    if (idxs.length < 2) return;
    idxs.forEach(i => {
      const base = updated[i].price || 0;
      updated[i] = {
        ...updated[i],
        price: Math.round(base * 0.8),
        priceBeforeSameDayDiscount: base,
        sameDayDiscount: true,
      };
    });
  });
  return updated;
}

function getWeekDates(weekOffset = 0) {
  const today = new Date();
  const dow = today.getDay();
  const offset = dow === 0 ? -6 : 1 - dow;
  const monday = new Date(today);
  monday.setDate(today.getDate() + offset + weekOffset * 7);
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    return d;
  });
}
// Parse a YYYY-MM-DD string as LOCAL midnight (not UTC) to avoid timezone-shift bugs
function parseDateLocal(dateStr) {
  const [y, m, d] = dateStr.split("-").map(Number);
  return new Date(y, m - 1, d);
}

function dateStrFromDate(d) {
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

// Simulated email verification code (in production this would be sent via email)
function generateCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// ─── Address Helpers ─────────────────────────────────────────────────────────
// Addresses are stored as { street, city, state, zip } plus a flat `address`
// string for display and geocoding.
function addrToString(a) {
  if (!a || typeof a === "string") return a || "";
  const parts = [a.street, a.city, a.state, a.zip].filter(Boolean);
  return parts.join(", ");
}
function addrFromString(s) {
  // Best-effort parse of "123 Main St, Dallas, TX 75201"
  if (!s) return { street: "", city: "", state: "", zip: "" };
  const parts = s.split(",").map(p => p.trim());
  return {
    street: parts[0] || "",
    city:   parts[1] || "",
    state:  parts[2] ? parts[2].replace(/\s+\d{5}.*/, "").trim() : "",
    zip:    parts[2] ? (parts[2].match(/\d{5}/) || [""])[0] : (parts[3] || ""),
  };
}
function emptyAddr() { return { street: "", city: "", state: "", zip: "" }; }

const US_STATES = new Set([
  "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA",
  "HI","ID","IL","IN","IA","KS","KY","LA","ME","MD",
  "MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ",
  "NM","NY","NC","ND","OH","OK","OR","PA","RI","SC",
  "SD","TN","TX","UT","VT","VA","WA","WV","WI","WY",
  "DC",
]);

// Phone formatter — strips non-digits, caps at 10, outputs xxx.xxx.xxxx
// Format a number or dollar amount with commas: fmt(1234.5) → "1,235"  fmt(1234.5, true) → "$1,235"
function fmt(n, dollars = false) {
  const num = typeof n === "string" ? parseFloat(n) : n;
  if (isNaN(num)) return dollars ? "$0" : "0";
  const rounded = Math.round(num);
  const formatted = rounded.toLocaleString("en-US");
  return dollars ? `$${formatted}` : formatted;
}

function formatPhone(raw) {
  const digits = (raw || "").replace(/\D/g, "").slice(0, 10);
  if (digits.length <= 3) return digits;
  if (digits.length <= 6) return `${digits.slice(0, 3)}.${digits.slice(3)}`;
  return `${digits.slice(0, 3)}.${digits.slice(3, 6)}.${digits.slice(6)}`;
}

// AddressFields component — ZIP first, auto-fills city/state, city forced uppercase
function AddressFields({ value, onChange, errors = {}, inputBaseStyle = {}, labelBaseStyle = {} }) {
  const addr = (value && typeof value === "object") ? value : addrFromString(value || "");
  const [zipLooking, setZipLooking] = useState(false);
  const [zipError, setZipError] = useState("");
  const [autoFilled, setAutoFilled] = useState(!!(addr.city && addr.state));

  const baseInput = {
    width: "100%", padding: "12px 14px", borderRadius: "10px",
    background: "#fff", fontSize: "16px", fontFamily: "'DM Sans', sans-serif",
    color: "#111827", outline: "none", transition: "border-color 0.15s",
    ...inputBaseStyle,
  };
  const baseLabel = {
    display: "block", fontFamily: "'DM Sans', sans-serif", fontSize: "15px",
    fontWeight: 600, letterSpacing: "1px", textTransform: "uppercase",
    color: "#9ca3af", marginBottom: "5px",
    ...labelBaseStyle,
  };
  const fieldBorder = (err) => `1.5px solid ${err ? "#ef4444" : "#d1d5db"}`;

  const update = (key, val) => {
    const next = { ...addr, [key]: val };
    onChange(next, addrToString(next));
  };

  const lookupZip = async (zip) => {
    if (zip.length !== 5) return;
    setZipLooking(true);
    setZipError("");
    try {
      const res = await fetch(`https://api.zippopotam.us/us/${zip}`);
      if (!res.ok) throw new Error("not found");
      const data = await res.json();
      const city  = (data.places[0]["place name"] || "").toUpperCase();
      const state = data.places[0]["state abbreviation"] || "";
      const next = { ...addr, zip, city, state };
      onChange(next, addrToString(next));
      setAutoFilled(true);
    } catch {
      setZipError("ZIP not found — please enter city and state manually.");
      setAutoFilled(false);
    } finally {
      setZipLooking(false);
    }
  };

  return (
    <div>
      {/* ZIP Code — first */}
      <div style={{ marginBottom: "10px" }}>
        <label style={baseLabel}>ZIP Code</label>
        <div style={{ position: "relative" }}>
          <input
            value={addr.zip}
            onChange={e => {
              const zip = e.target.value.replace(/\D/g, "").slice(0, 5);
              update("zip", zip);
              setZipError("");
              if (zip.length < 5) setAutoFilled(false);
              if (zip.length === 5) lookupZip(zip);
            }}
            placeholder="75201"
            maxLength={5}
            inputMode="numeric"
            style={{ ...baseInput, border: fieldBorder(errors.zip || zipError),
              paddingRight: zipLooking ? "40px" : "14px" }}
          />
          {zipLooking && (
            <div style={{ position: "absolute", right: "12px", top: "50%", transform: "translateY(-50%)",
              fontFamily: "'DM Sans', sans-serif", fontSize: "15px", color: "#9ca3af" }}>
              …
            </div>
          )}
        </div>
        {(errors.zip || zipError) && (
          <div style={{ color: "#ef4444", fontFamily: "'DM Sans', sans-serif",
            fontSize: "15px", marginTop: "3px" }}>{errors.zip || zipError}</div>
        )}
      </div>

      {/* City + State row — auto-filled from ZIP */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 80px", gap: "8px", marginBottom: "10px" }}>
        <div>
          <label style={baseLabel}>
            City{autoFilled && <span style={{ marginLeft: "6px", color: "#D4A843", fontWeight: 400,
              letterSpacing: 0, textTransform: "none", fontSize: "16px" }}>auto-filled</span>}
          </label>
          <input
            value={addr.city}
            onChange={e => update("city", e.target.value.toUpperCase())}
            placeholder="DALLAS"
            readOnly={autoFilled}
            style={{ ...baseInput, border: fieldBorder(errors.city),
              background: autoFilled ? "#f9fafb" : "#fff",
              color: "#111827", textTransform: "uppercase" }}
          />
          {errors.city && <div style={{ color: "#ef4444", fontFamily: "'DM Sans', sans-serif",
            fontSize: "15px", marginTop: "3px" }}>{errors.city}</div>}
        </div>
        <div>
          <label style={baseLabel}>
            State{autoFilled && <span style={{ marginLeft: "6px", color: "#D4A843", fontWeight: 400,
              letterSpacing: 0, textTransform: "none", fontSize: "16px" }}>auto-filled</span>}
          </label>
          <input
            value={addr.state}
            onChange={e => update("state", e.target.value.replace(/[^a-zA-Z]/g, "").slice(0, 2).toUpperCase())}
            placeholder="TX"
            maxLength={2}
            readOnly={autoFilled}
            style={{ ...baseInput, border: fieldBorder(
              errors.state || (addr.state.length === 2 && !US_STATES.has(addr.state))
            ), background: autoFilled ? "#f9fafb" : "#fff" }}
          />
          {(errors.state || (addr.state.length === 2 && !US_STATES.has(addr.state))) && (
            <div style={{ color: "#ef4444", fontFamily: "'DM Sans', sans-serif",
              fontSize: "15px", marginTop: "3px" }}>
              {errors.state || "Not a valid US state code"}
            </div>
          )}
        </div>
      </div>

      {/* Street */}
      <div>
        <label style={baseLabel}>Street Address</label>
        <input
          value={addr.street}
          onChange={e => update("street", e.target.value)}
          placeholder="123 Main St"
          style={{ ...baseInput, border: fieldBorder(errors.street) }}
        />
        {errors.street && <div style={{ color: "#ef4444", fontFamily: "'DM Sans', sans-serif",
          fontSize: "15px", marginTop: "3px" }}>{errors.street}</div>}
      </div>
    </div>
  );
}

