// ─── Logo Badge (inline SVG — no image file needed) ──────────────────────────
function LogoBadge({ size = 48 }) {
  const cx = size / 2;
  const cy = size / 2;
  const r  = size / 2 - 0.5;
  const sc = size / 76;   // design reference: 76px diameter

  // Star: 5-pointed, pointing UP in SVG (y-down) — start angle -90deg
  function starPoints(scx, scy, outerR, innerR) {
    const pts = [];
    for (let i = 0; i < 10; i++) {
      const angle = (Math.PI / 5) * i - Math.PI / 2;  // -90° + i*36°
      const rad   = i % 2 === 0 ? outerR : innerR;
      pts.push(`${scx + rad * Math.cos(angle)},${scy + rad * Math.sin(angle)}`);
    }
    return pts.join(" ");
  }

  // Geometry scaled from 76px reference:
  // star center at cy-14/38*sc, outer=12sc, inner=4.8sc
  // paw center at cy+19/38*sc, with clear gap from star
  const starCY  = cy - 14 * sc;
  const starOut = 12 * sc;
  const starIn  = 4.8 * sc;
  const pawCY   = cy + 19 * sc;
  const toeR    = 4.0 * sc;
  const toeRY   = 3.4 * sc;
  const mainRX  = 8.5 * sc;
  const mainRY  = 6.5 * sc;

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}
      style={{ display: "block", flexShrink: 0 }}>
      <circle cx={cx} cy={cy} r={r} fill="#0B1423" />
      <circle cx={cx} cy={cy} r={r - 1.5 * sc} fill="none" stroke="#D4A843" strokeWidth={Math.max(0.5, 1.2 * sc)} />
      <circle cx={cx} cy={cy} r={r - 5 * sc}   fill="none" stroke="#D4A843" strokeWidth={Math.max(0.3, 0.5 * sc)} />
      <polygon points={starPoints(cx, starCY, starOut, starIn)} fill="#D4A843" />
      <ellipse cx={cx - 11 * sc} cy={pawCY - 14.5 * sc} rx={toeR} ry={toeRY} fill="#C4541A" />
      <ellipse cx={cx - 3.8 * sc} cy={pawCY - 17.5 * sc} rx={toeR} ry={toeRY} fill="#C4541A" />
      <ellipse cx={cx + 3.8 * sc} cy={pawCY - 17.5 * sc} rx={toeR} ry={toeRY} fill="#C4541A" />
      <ellipse cx={cx + 11 * sc}  cy={pawCY - 14.5 * sc} rx={toeR} ry={toeRY} fill="#C4541A" />
      <ellipse cx={cx} cy={pawCY + sc} rx={mainRX} ry={mainRY} fill="#C4541A" />
    </svg>
  );
}

